function o(){const t=new Date,n=t.getFullYear(),r=String(t.getMonth()+1).padStart(2,"0"),e=String(t.getDate()).padStart(2,"0");return`${n}-${r}-${e}`}function a(t){if(!t)return"-";const[n,r,e]=t.split("-");return`${e}/${r}/${n}`}function c(t){return Number(t||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"})}function s(t){if(!t)return 0;const[n,r]=String(t).slice(0,5).split(":").map(Number);return n*60+r}export{a,s as b,c as f,o as t};
